package adminhandlers

import (
	"encoding/json"
	"errors"
	"fmt"
	"math/rand"
	"net/http"
	"socialpredict/handlers"
	"socialpredict/handlers/authhttp"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/logger"
	"socialpredict/models"
	"socialpredict/security"
	"strings"

	"github.com/brianvoe/gofakeit"
	"gorm.io/gorm"
)

func AddUserHandler(db *gorm.DB, configService configsvc.Service, auth authsvc.Authenticator) func(http.ResponseWriter, *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		responseData, handlerErr := processAddUser(r, db, configService, auth)
		if handlerErr != nil {
			_ = handlers.WriteFailure(w, handlerErr.statusCode, handlerErr.reason)
			logAddUserFailure(handlerErr)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(responseData)
		if username, ok := responseData["username"].(string); ok {
			logger.LogInfo("AddUser", "ProcessAddUser", "Created user "+username)
		}
	}
}

type handlerError struct {
	message    string
	statusCode int
	logErr     error
	reason     handlers.FailureReason
}

func processAddUser(r *http.Request, db *gorm.DB, configService configsvc.Service, auth authsvc.Authenticator) (map[string]interface{}, *handlerError) {
	securityService := security.NewSecurityService()
	req, decodeErr := decodeAddUserRequest(r)
	if decodeErr != nil {
		return nil, &handlerError{
			message:    decodeErr.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     decodeErr,
			reason:     handlers.ReasonInvalidRequest,
		}
	}

	if err := validateAddUserUsername(securityService, req.Username); err != nil {
		return nil, &handlerError{
			message:    "Invalid username: " + err.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     err,
			reason:     handlers.ReasonValidationFailed,
		}
	}
	req.Username, _ = securityService.Sanitizer.SanitizeUsername(req.Username)

	if db == nil {
		return nil, &handlerError{message: "database unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	if auth == nil {
		return nil, &handlerError{message: "authentication service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}
	if _, authErr := auth.RequireAdmin(r); authErr != nil {
		return nil, &handlerError{
			message:    authErr.Message,
			statusCode: authhttp.StatusCode(authErr),
			logErr:     errors.New(authErr.Message),
			reason:     authhttp.FailureReason(authErr),
		}
	}

	if configService == nil {
		return nil, &handlerError{message: "configuration service unavailable", statusCode: http.StatusInternalServerError, reason: handlers.ReasonInternalError}
	}

	appConfig := configService.Current()
	user := buildNewUser(db, req.Username, appConfig)

	if err := checkUniqueFields(db, &user); err != nil {
		return nil, &handlerError{
			message:    err.Error(),
			statusCode: http.StatusBadRequest,
			logErr:     err,
			reason:     handlers.ReasonValidationFailed,
		}
	}

	password, err := generateAndHashPassword(&user)
	if err != nil {
		return nil, &handlerError{
			message:    err.Error(),
			statusCode: http.StatusInternalServerError,
			logErr:     err,
			reason:     handlers.ReasonInternalError,
		}
	}

	if result := db.Create(&user); result.Error != nil {
		return nil, &handlerError{
			message:    "Failed to create user",
			statusCode: http.StatusInternalServerError,
			logErr:     result.Error,
			reason:     handlers.ReasonInternalError,
		}
	}

	responseData := map[string]interface{}{
		"message":  "User created successfully",
		"username": user.Username,
		"password": password,
		"usertype": user.UserType,
	}
	return responseData, nil
}

type addUserRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
}

func decodeAddUserRequest(r *http.Request) (addUserRequest, error) {
	var req addUserRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return addUserRequest{}, fmt.Errorf("Error decoding request body")
	}
	return req, nil
}

func validateAddUserUsername(securityService *security.SecurityService, username string) error {
	if err := securityService.Validator.ValidateStruct(addUserRequest{Username: username}); err != nil {
		return err
	}
	_, err := securityService.Sanitizer.SanitizeUsername(username)
	return err
}

func buildNewUser(db *gorm.DB, username string, appConfig *configsvc.AppConfig) models.User {
	return models.User{
		PublicUser: models.PublicUser{
			Username:              username,
			DisplayName:           dusers.UniqueDisplayName(db),
			UserType:              "REGULAR",
			InitialAccountBalance: appConfig.Economics.User.InitialAccountBalance,
			AccountBalance:        appConfig.Economics.User.InitialAccountBalance,
			PersonalEmoji:         randomEmoji(),
		},
		PrivateUser: models.PrivateUser{
			Email:  dusers.UniqueEmail(db),
			APIKey: dusers.GenerateUniqueAPIKey(db),
		},
		MustChangePassword: true,
	}
}

func generateAndHashPassword(user *models.User) (string, error) {
	password := gofakeit.Password(true, true, true, false, false, 12)
	if err := user.HashPassword(password); err != nil {
		return "", fmt.Errorf("Failed to hash password")
	}
	return password, nil
}

func checkUniqueFields(db *gorm.DB, user *models.User) error {
	// Check for existing users with the same username, display name, email, or API key.
	var count int64
	db.Model(&models.User{}).Where(
		"username = ? OR display_name = ? OR email = ? OR api_key = ?",
		user.Username, user.DisplayName, user.Email, user.APIKey,
	).Count(&count)

	if count > 0 {
		return fmt.Errorf("username, display name, email, or API key already in use")
	}

	return nil
}

func randomEmoji() string {
	emojis := []string{"😀", "😃", "😄", "😁", "😆"}
	return emojis[rand.Intn(len(emojis))]
}

func logAddUserFailure(handlerErr *handlerError) {
	if handlerErr == nil || handlerErr.logErr == nil {
		return
	}

	if handlerErr.statusCode >= http.StatusInternalServerError {
		logger.LogError("AddUser", "ProcessAddUser", handlerErr.logErr)
		return
	}

	message := strings.TrimSpace(handlerErr.message)
	if message == "" {
		message = handlerErr.logErr.Error()
	}
	logger.LogWarn("AddUser", "ProcessAddUser", message)
}

package statshandlers

import (
	"net/http"
	"socialpredict/handlers"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/models"

	"gorm.io/gorm"
)

type FinancialStats struct {
	TotalMoney              int64 `json:"totalMoney"`
	TotalDebtExtended       int64 `json:"totalDebtExtended"`
	TotalDebtUtilized       int64 `json:"totalDebtUtilized"`
	TotalFeesCollected      int64 `json:"totalFeesCollected"`
	TotalBonusesPaid        int64 `json:"totalBonusesPaid"`
	OutstandingPayouts      int64 `json:"outstandingPayouts"`
	TotalMoneyInCirculation int64 `json:"totalMoneyInCirculation"` // Money currently active in bets
}

type SetupConfiguration struct {
	InitialMarketProbability   float64 `json:"initialMarketProbability"`
	InitialMarketSubsidization int64   `json:"initialMarketSubsidization"`
	InitialMarketYes           int64   `json:"initialMarketYes"`
	InitialMarketNo            int64   `json:"initialMarketNo"`
	CreateMarketCost           int64   `json:"createMarketCost"`
	TraderBonus                int64   `json:"traderBonus"`
	InitialAccountBalance      int64   `json:"initialAccountBalance"`
	MaximumDebtAllowed         int64   `json:"maximumDebtAllowed"`
	MinimumBet                 int64   `json:"minimumBet"`
	MaxDustPerSale             int64   `json:"maxDustPerSale"`
	InitialBetFee              int64   `json:"initialBetFee"`
	BuySharesFee               int64   `json:"buySharesFee"`
	SellSharesFee              int64   `json:"sellSharesFee"`
}

type StatsResponse struct {
	FinancialStats     FinancialStats     `json:"financialStats"`
	SetupConfiguration SetupConfiguration `json:"setupConfiguration"`
}

// StatsHandler handles requests for both financial stats and setup configuration.
func StatsHandler(db *gorm.DB, configService configsvc.Service) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if db == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}
		if configService == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		economics := configService.Economics()

		financialStats, err := calculateFinancialStats(db, economics)
		if err != nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		setupConfig := loadSetupConfiguration(economics)

		response := StatsResponse{
			FinancialStats:     financialStats,
			SetupConfiguration: setupConfig,
		}

		if err := handlers.WriteResult(w, http.StatusOK, response); err != nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
		}
	}
}

func calculateFinancialStats(db *gorm.DB, economics configsvc.Economics) (FinancialStats, error) {
	var result FinancialStats

	totalMoney, err := calculateTotalMoney(db, economics.User)
	if err != nil {
		return result, err
	}
	result.TotalMoney = totalMoney

	result.TotalDebtExtended = 0
	result.TotalDebtUtilized = 0
	result.TotalFeesCollected = 0
	result.TotalBonusesPaid = 0
	result.OutstandingPayouts = 0
	result.TotalMoneyInCirculation = 0

	return result, nil
}

func calculateTotalMoney(db *gorm.DB, userConfig configsvc.User) (int64, error) {
	var userCount int64
	if err := db.Model(&models.User{}).Where("user_type = ?", "REGULAR").Count(&userCount).Error; err != nil {
		return 0, err
	}

	totalMoney := userConfig.InitialAccountBalance * userCount
	return totalMoney, nil
}

func loadSetupConfiguration(economics configsvc.Economics) SetupConfiguration {
	var result SetupConfiguration

	result.InitialMarketProbability = economics.MarketCreation.InitialMarketProbability
	result.InitialMarketSubsidization = economics.MarketCreation.InitialMarketSubsidization
	result.InitialMarketYes = economics.MarketCreation.InitialMarketYes
	result.InitialMarketNo = economics.MarketCreation.InitialMarketNo
	result.CreateMarketCost = economics.MarketIncentives.CreateMarketCost
	result.TraderBonus = economics.MarketIncentives.TraderBonus
	result.InitialAccountBalance = economics.User.InitialAccountBalance
	result.MaximumDebtAllowed = economics.User.MaximumDebtAllowed
	result.MinimumBet = economics.Betting.MinimumBet
	result.MaxDustPerSale = economics.Betting.MaxDustPerSale
	result.InitialBetFee = economics.Betting.BetFees.InitialBetFee
	result.BuySharesFee = economics.Betting.BetFees.BuySharesFee
	result.SellSharesFee = economics.Betting.BetFees.SellSharesFee

	return result
}

package users

import (
	"errors"
	"fmt"

	"socialpredict/models"

	"github.com/brianvoe/gofakeit"
	"github.com/google/uuid"
	"gorm.io/gorm"
)

func CheckUserIsReal(db *gorm.DB, username string) error {
	var user models.User
	result := db.Where("username = ?", username).First(&user)
	if result.Error != nil {
		if errors.Is(result.Error, gorm.ErrRecordNotFound) {
			return errors.New("creator user not found")
		}
		return result.Error
	}
	return nil
}

func CountByField(db *gorm.DB, field, value string) int64 {
	var count int64
	db.Model(&models.User{}).Where(fmt.Sprintf("%s = ?", field), value).Count(&count)
	return count
}

func UniqueDisplayName(db *gorm.DB) string {
	for {
		name := gofakeit.Name()
		if count := CountByField(db, "display_name", name); count == 0 {
			return name
		}
	}
}

func UniqueEmail(db *gorm.DB) string {
	for {
		email := gofakeit.Email()
		if count := CountByField(db, "email", email); count == 0 {
			return email
		}
	}
}

func GenerateUniqueAPIKey(db *gorm.DB) string {
	for {
		apiKey := uuid.NewString()
		if count := CountByField(db, "api_key", apiKey); count == 0 {
			return apiKey
		}
	}
}

package analytics

import (
	"context"
	"errors"
	"sort"
	"time"

	"socialpredict/internal/domain/boundary"
	positionsmath "socialpredict/internal/domain/math/positions"

	"gorm.io/gorm"
)

// GormRepository implements the analytics repository interface using GORM.
type GormRepository struct {
	db                 *gorm.DB
	positionCalculator MarketPositionCalculator
}

// RepositoryOption configures the GormRepository strategies.
type RepositoryOption func(*GormRepository)

func defaultRepositoryPositionCalculator() MarketPositionCalculator {
	return defaultMarketPositionCalculator{}
}

func positionCalculatorOrDefault(calculator MarketPositionCalculator) MarketPositionCalculator {
	if calculator == nil {
		return defaultRepositoryPositionCalculator()
	}
	return calculator
}

// WithRepositoryPositionCalculator overrides the default position calculator for the repository.
func WithRepositoryPositionCalculator(c MarketPositionCalculator) RepositoryOption {
	return func(r *GormRepository) {
		if r != nil {
			r.positionCalculator = positionCalculatorOrDefault(c)
		}
	}
}

// NewGormRepository constructs a GORM-backed analytics repository.
func NewGormRepository(db *gorm.DB, opts ...RepositoryOption) *GormRepository {
	repo := &GormRepository{
		db:                 db,
		positionCalculator: defaultRepositoryPositionCalculator(),
	}
	for _, opt := range opts {
		opt(repo)
	}
	return repo
}

func (r *GormRepository) WithContext(ctx context.Context) *gorm.DB {
	if r == nil || r.db == nil {
		return nil
	}
	if ctx == nil {
		return r.db
	}
	return r.db.WithContext(ctx)
}

func (r *GormRepository) dbWithContext(ctx context.Context) (*gorm.DB, error) {
	db := r.WithContext(ctx)
	if db == nil {
		return nil, errors.New("gorm repository not initialized")
	}
	return db, nil
}

func (r *GormRepository) ListUsers(ctx context.Context) ([]UserAccount, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var users []analyticsUserRow
	if err := db.Table("users").
		Select("username", "account_balance").
		Find(&users).Error; err != nil {
		return nil, err
	}
	return mapUsers(users), nil
}

func (r *GormRepository) ListMarkets(ctx context.Context) ([]MarketRecord, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var markets []analyticsMarketRow
	if err := db.Table("markets").
		Select("id", "created_at", "is_resolved", "resolution_result").
		Find(&markets).Error; err != nil {
		return nil, err
	}
	return mapMarkets(markets), nil
}

func (r *GormRepository) ListBetsForMarket(ctx context.Context, marketID uint) ([]boundary.Bet, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var bets []analyticsBetRow
	if err := db.Table("bets").
		Select("id", "username", "market_id", "amount", "outcome", "placed_at", "created_at").
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}
	return mapBets(bets), nil
}

func (r *GormRepository) ListBetsOrdered(ctx context.Context) ([]boundary.Bet, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}
	var bets []analyticsBetRow
	if err := db.Table("bets").
		Select("id", "username", "market_id", "amount", "outcome", "placed_at", "created_at").
		Order("market_id ASC, placed_at ASC, id ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}
	return mapBets(bets), nil
}

func (r *GormRepository) UserMarketPositions(ctx context.Context, username string) ([]positionsmath.MarketPosition, error) {
	db, err := r.dbWithContext(ctx)
	if err != nil {
		return nil, err
	}

	userBets, err := r.listUserBets(db, username)
	if err != nil {
		return nil, err
	}
	if len(userBets) == 0 {
		return []positionsmath.MarketPosition{}, nil
	}

	marketIDs := collectMarketIDs(userBets)

	markets, err := r.listMarketsByIDs(db, marketIDs)
	if err != nil {
		return nil, err
	}

	snapshots := buildMarketSnapshots(markets)

	allBets, err := r.listBetsByMarketIDs(db, marketIDs)
	if err != nil {
		return nil, err
	}

	betsByMarket := groupBetsByMarket(allBets)
	calculator := r.ensurePositionCalculator()

	positions, err := r.calculateUserPositions(calculator, username, marketIDs, snapshots, betsByMarket)
	if err != nil {
		return nil, err
	}

	return positions, nil
}

func (r *GormRepository) listUserBets(db *gorm.DB, username string) ([]boundary.Bet, error) {
	var userBets []analyticsBetRow
	if err := db.Table("bets").
		Select("id", "username", "market_id", "amount", "outcome", "placed_at", "created_at").
		Where("username = ?", username).
		Order("market_id ASC, placed_at ASC, id ASC").
		Find(&userBets).Error; err != nil {
		return nil, err
	}
	return mapBets(userBets), nil
}

func collectMarketIDs(bets []boundary.Bet) []uint {
	marketIDSet := make(map[uint]struct{}, len(bets))
	for _, bet := range bets {
		marketIDSet[bet.MarketID] = struct{}{}
	}

	marketIDs := make([]uint, 0, len(marketIDSet))
	for id := range marketIDSet {
		marketIDs = append(marketIDs, uint(id))
	}
	sort.Slice(marketIDs, func(i, j int) bool { return marketIDs[i] < marketIDs[j] })
	return marketIDs
}

func (r *GormRepository) listMarketsByIDs(db *gorm.DB, marketIDs []uint) ([]MarketRecord, error) {
	if len(marketIDs) == 0 {
		return []MarketRecord{}, nil
	}
	var markets []analyticsMarketRow
	if err := db.Table("markets").
		Select("id", "created_at", "is_resolved", "resolution_result").
		Where("id IN ?", marketIDs).
		Find(&markets).Error; err != nil {
		return nil, err
	}
	return mapMarkets(markets), nil
}

func buildMarketSnapshots(markets []MarketRecord) map[int64]positionsmath.MarketSnapshot {
	marketSnapshots := make(map[int64]positionsmath.MarketSnapshot, len(markets))
	for _, market := range markets {
		marketSnapshots[int64(market.ID)] = market.Snapshot()
	}
	return marketSnapshots
}

func (r *GormRepository) listBetsByMarketIDs(db *gorm.DB, marketIDs []uint) ([]boundary.Bet, error) {
	if len(marketIDs) == 0 {
		return []boundary.Bet{}, nil
	}
	var allBets []analyticsBetRow
	if err := db.Table("bets").
		Select("id", "username", "market_id", "amount", "outcome", "placed_at", "created_at").
		Where("market_id IN ?", marketIDs).
		Order("market_id ASC, placed_at ASC, id ASC").
		Find(&allBets).Error; err != nil {
		return nil, err
	}
	return mapBets(allBets), nil
}

func groupBetsByMarket(bets []boundary.Bet) map[int64][]boundary.Bet {
	betsByMarket := make(map[int64][]boundary.Bet, len(bets))
	for _, bet := range bets {
		betsByMarket[int64(bet.MarketID)] = append(betsByMarket[int64(bet.MarketID)], bet)
	}
	return betsByMarket
}

func (r *GormRepository) ensurePositionCalculator() MarketPositionCalculator {
	if r == nil {
		return defaultRepositoryPositionCalculator()
	}
	r.positionCalculator = positionCalculatorOrDefault(r.positionCalculator)
	return r.positionCalculator
}

func (r *GormRepository) calculateUserPositions(calculator MarketPositionCalculator, username string, marketIDs []uint, snapshots map[int64]positionsmath.MarketSnapshot, betsByMarket map[int64][]boundary.Bet) ([]positionsmath.MarketPosition, error) {
	var positions []positionsmath.MarketPosition
	for _, marketID := range marketIDs {
		snapshot, ok := snapshots[int64(marketID)]
		if !ok {
			continue
		}

		bets := betsByMarket[int64(marketID)]
		if len(bets) == 0 {
			continue
		}

		calculated, err := calculator.Calculate(snapshot, bets)
		if err != nil {
			return nil, err
		}

		for _, pos := range calculated {
			if pos.Username == username {
				positions = append(positions, pos)
				break
			}
		}
	}

	return positions, nil
}

