		t.Fatalf("persist must_change_password=%t: %v", mustChangePassword, err)
	}

	return modelstesting.GenerateValidJWT(username)
}

func TestAddUserHandler_ReturnsFailureEnvelopes(t *testing.T) {
	t.Setenv("JWT_SIGNING_KEY", "test-secret-key-for-testing")

	tests := []struct {
		name       string
		seedUser   bool
		username   string
		userType   string
		mustChange bool
		authHeader string
		body       string
		wantStatus int
		wantReason handlers.FailureReason
	}{
		{
			name:       "invalid token",
			authHeader: "Bearer invalid.token",
			body:       `{"username":"freshuser"}`,
			wantStatus: http.StatusUnauthorized,
			wantReason: handlers.ReasonInvalidToken,
		},
		{
			name:       "missing auth user",
			authHeader: "Bearer " + modelstesting.GenerateValidJWT("missing-admin"),
			body:       `{"username":"freshuser"}`,
			wantStatus: http.StatusNotFound,
			wantReason: handlers.ReasonUserNotFound,
		},
		{
			name:       "password change required",
			seedUser:   true,
			username:   "adminneedsreset",
			userType:   "ADMIN",
			mustChange: true,
			body:       `{"username":"freshuser"}`,
			wantStatus: http.StatusForbidden,
			wantReason: handlers.ReasonPasswordChangeRequired,
		},
		{
			name:       "non-admin caller",
			seedUser:   true,
			username:   "regularuser",
			userType:   "REGULAR",
			body:       `{"username":"freshuser"}`,
			wantStatus: http.StatusForbidden,
			wantReason: handlers.ReasonAuthorizationDenied,
		},
		{
			name:       "invalid username",
			seedUser:   true,
			username:   "admincreator",
			userType:   "ADMIN",
			body:       `{"username":"BadName"}`,
			wantStatus: http.StatusBadRequest,
			wantReason: handlers.ReasonValidationFailed,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			handler, db := buildAddUserTestHandler(t)

			authHeader := tt.authHeader
			if tt.seedUser {
				authHeader = "Bearer " + createAddUserAuthSubject(t, db, tt.username, tt.userType, tt.mustChange)
			}

			req := httptest.NewRequest(http.MethodPost, "/v0/admin/createuser", bytes.NewBufferString(tt.body))
			req.Header.Set("Authorization", authHeader)
			rec := httptest.NewRecorder()

			handler.ServeHTTP(rec, req)

			if rec.Code != tt.wantStatus {
				t.Fatalf("expected status %d, got %d: %s", tt.wantStatus, rec.Code, rec.Body.String())
			}

			var response handlers.FailureEnvelope
			if err := json.Unmarshal(rec.Body.Bytes(), &response); err != nil {
				t.Fatalf("decode failure response: %v", err)
			}
			if response.OK || response.Reason != string(tt.wantReason) {
				t.Fatalf("expected reason %q, got %+v", tt.wantReason, response)
			}
		})
	}
}

func TestAddUserHandler_CreatesUserWithPlainSuccessResponse(t *testing.T) {
	t.Setenv("JWT_SIGNING_KEY", "test-secret-key-for-testing")

	handler, db := buildAddUserTestHandler(t)
	token := createAddUserAuthSubject(t, db, "admincreator", "ADMIN", false)

	req := httptest.NewRequest(http.MethodPost, "/v0/admin/createuser", bytes.NewBufferString(`{"username":"freshuser"}`))
	req.Header.Set("Authorization", "Bearer "+token)
	rec := httptest.NewRecorder()

	handler.ServeHTTP(rec, req)

	if rec.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d: %s", rec.Code, rec.Body.String())
	}

	var response struct {
		Message  string `json:"message"`
		Username string `json:"username"`
		Password string `json:"password"`
		UserType string `json:"usertype"`
	}
	if err := json.Unmarshal(rec.Body.Bytes(), &response); err != nil {
		t.Fatalf("decode success response: %v", err)
	}

	if response.Message != "User created successfully" {
		t.Fatalf("expected success message, got %q", response.Message)
	}
	if response.Username != "freshuser" {
		t.Fatalf("expected username freshuser, got %q", response.Username)
	}
	if response.Password == "" {
		t.Fatalf("expected generated password in response")
	}
	if response.UserType != "REGULAR" {
		t.Fatalf("expected REGULAR user type, got %q", response.UserType)
	}

	var created models.User
	if err := db.Where("username = ?", "freshuser").First(&created).Error; err != nil {
		t.Fatalf("load created user: %v", err)
	}
	if !created.MustChangePassword {
		t.Fatalf("expected created user to require password change")
	}
}

package users

import (
	"time"
)

const personalLinkFieldCount = 4

// PersonalLinksTarget exposes the minimal contract needed to receive personal links.
type PersonalLinksTarget interface {
	ApplyPersonalLinks(PersonalLinks)
}

// User represents the core user domain model
type User struct {
	ID                    int64
	Username              string
	DisplayName           string
	Email                 string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
	APIKey                string
	MustChangePassword    bool
	CreatedAt             time.Time
	UpdatedAt             time.Time
}

// ToPublicUser returns the public-safe projection of the user model.
func (u *User) ToPublicUser() *PublicUser {
	return new(PublicUser).FromUser(u)
}

// ToPrivateProfile returns the authenticated private projection of the user model.
func (u *User) ToPrivateProfile() *PrivateProfile {
	return new(PrivateProfile).FromUser(u)
}

func copyPublicUser(target *PublicUser, user *User) *PublicUser {
	if user == nil {
		return nil
	}

	if target == nil {
		target = &PublicUser{}
	}

	*target = PublicUser{
		ID:                    user.ID,
		Username:              user.Username,
		DisplayName:           user.DisplayName,
		UserType:              user.UserType,
		InitialAccountBalance: user.InitialAccountBalance,
		AccountBalance:        user.AccountBalance,
		PersonalEmoji:         user.PersonalEmoji,
		Description:           user.Description,
	}
	user.PersonalLinks().ApplyTo(target)
	return target
}

// FromUser copies the public-safe projection of the user model.
func (u *PublicUser) FromUser(user *User) *PublicUser {
	return copyPublicUser(u, user)
}

func copyPrivateProfile(target *PrivateProfile, user *User) *PrivateProfile {
	if user == nil {
		return nil
	}

	if target == nil {
		target = &PrivateProfile{}
	}

	*target = PrivateProfile{
		ID:                    user.ID,
		Username:              user.Username,
		DisplayName:           user.DisplayName,
		UserType:              user.UserType,
		InitialAccountBalance: user.InitialAccountBalance,
		AccountBalance:        user.AccountBalance,
		PersonalEmoji:         user.PersonalEmoji,
		Description:           user.Description,
		Email:                 user.Email,
		APIKey:                user.APIKey,
		MustChangePassword:    user.MustChangePassword,
		CreatedAt:             user.CreatedAt,
		UpdatedAt:             user.UpdatedAt,
	}
	user.PersonalLinks().ApplyTo(target)
	return target
}

// FromUser copies the authenticated private projection of the user model.
func (p *PrivateProfile) FromUser(user *User) *PrivateProfile {
	return copyPrivateProfile(p, user)
}

// ApplyUpdate mutates the user with the fields supported by UserUpdateRequest.
func (u *User) ApplyUpdate(req UserUpdateRequest) {
	if u == nil {
		return
	}

	u.DisplayName = req.DisplayName
	u.Description = req.Description
	u.PersonalEmoji = req.PersonalEmoji
	req.PersonalLinks().ApplyTo(u)
}

// PersonalLinks returns the personal-link fields currently stored on the user.
func (u *User) PersonalLinks() PersonalLinks {
	if u == nil {
		return PersonalLinks{}
	}

	return PersonalLinks{
		PersonalLink1: u.PersonalLink1,
		PersonalLink2: u.PersonalLink2,
		PersonalLink3: u.PersonalLink3,
		PersonalLink4: u.PersonalLink4,
	}
}

// PublicUser represents the public view of a user
type PublicUser struct {
	ID                    int64
	Username              string
	DisplayName           string
	UserType              string
	InitialAccountBalance int64
	AccountBalance        int64
	PersonalEmoji         string
	Description           string
	PersonalLink1         string
	PersonalLink2         string
	PersonalLink3         string
	PersonalLink4         string
}

// UserCreateRequest represents the data needed to create a new user
type UserCreateRequest struct {
	Username    string
	DisplayName string
	Email       string
	Password    string
	UserType    string
}

// NewUser builds the default domain user entity for the request.
func (r UserCreateRequest) NewUser() *User {
	return &User{
		Username:              r.Username,
		DisplayName:           r.DisplayName,
		Email:                 r.Email,
		UserType:              r.UserType,
		InitialAccountBalance: 0,
		AccountBalance:        0,
		MustChangePassword:    true,
	}
}

// UserUpdateRequest represents the data that can be updated for a user
type UserUpdateRequest struct {
	DisplayName   string
	Description   string
	PersonalEmoji string
	PersonalLink1 string
	PersonalLink2 string
	PersonalLink3 string
	PersonalLink4 string
}

// PersonalLinks returns the request's personal-link values in the domain storage shape.
func (r UserUpdateRequest) PersonalLinks() PersonalLinks {
	return PersonalLinks{
		PersonalLink1: r.PersonalLink1,
		PersonalLink2: r.PersonalLink2,
		PersonalLink3: r.PersonalLink3,
		PersonalLink4: r.PersonalLink4,
	}
}

// UserBet represents a bet placed by a user.
type UserBet struct {
	MarketID uint
	PlacedAt time.Time
}

// MarketUserPosition represents a user's position within a market.
type MarketUserPosition struct {
	YesSharesOwned int64
	NoSharesOwned  int64
}

// PortfolioItem captures aggregate information for a market within a user's portfolio.
type PortfolioItem struct {
	MarketID       uint
	QuestionTitle  string
	YesSharesOwned int64
	NoSharesOwned  int64
	LastBetPlaced  time.Time
}

// Portfolio represents the user's overall market positions.
type Portfolio struct {
	Items            []PortfolioItem
	TotalSharesOwned int64
}

// UserMarket represents a market a user has participated in.
type UserMarket struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	UTCOffset               int
	IsResolved              bool
	ResolutionResult        string
	InitialProbability      float64
	YesLabel                string
	NoLabel                 string
	CreatorUsername         string
	CreatedAt               time.Time
	UpdatedAt               time.Time
}

// PersonalLinks captures the set of personal links associated with a user profile.
type PersonalLinks struct {
	PersonalLink1 string
	PersonalLink2 string
	PersonalLink3 string
	PersonalLink4 string
}

// Values returns the links in storage order for bulk validation or sanitization.
func (p PersonalLinks) Values() []string {
	return []string{
		p.PersonalLink1,
		p.PersonalLink2,
		p.PersonalLink3,
		p.PersonalLink4,
	}
}

// NewPersonalLinks rebuilds personal links from an ordered value slice.
func NewPersonalLinks(values []string) PersonalLinks {
	if len(values) > personalLinkFieldCount {
		values = values[:personalLinkFieldCount]
	}

package users

import (
	"context"
	"errors"

	"socialpredict/internal/domain/boundary"
	positionsmath "socialpredict/internal/domain/math/positions"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/models"

	"gorm.io/gorm"
)

// GormRepository implements the users domain repository interface using GORM
type GormRepository struct {
	db *gorm.DB
}

type authenticatedUserRow struct {
	Username           string
	UserType           string
	Password           string
	MustChangePassword bool
}

// NewGormRepository creates a new GORM-based users repository
func NewGormRepository(db *gorm.DB) *GormRepository {
	return &GormRepository{db: db}
}

// GetByUsername retrieves a user by username
func (r *GormRepository) GetByUsername(ctx context.Context, username string) (*dusers.User, error) {
	var dbUser models.User

	err := r.db.WithContext(ctx).Where("username = ?", username).First(&dbUser).Error
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dusers.ErrUserNotFound
		}
		return nil, err
	}

	return r.modelToDomain(&dbUser), nil
}

// UpdateBalance updates a user's account balance
func (r *GormRepository) UpdateBalance(ctx context.Context, username string, newBalance int64) error {
	result := r.db.WithContext(ctx).Model(&models.User{}).
		Where("username = ?", username).
		Update("account_balance", newBalance)

	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dusers.ErrUserNotFound
	}

	return nil
}

// Create creates a new user in the database
func (r *GormRepository) Create(ctx context.Context, user *dusers.User) error {
	dbUser := r.domainToModel(user)

	result := r.db.WithContext(ctx).Create(&dbUser)
	if result.Error != nil {
		// Check for unique constraint violations
		if errors.Is(result.Error, gorm.ErrDuplicatedKey) {
			return dusers.ErrUserAlreadyExists
		}
		return result.Error
	}

	// Update the domain model with the generated ID
	user.ID = dbUser.ID
	return nil
}

// Update updates a user in the database
func (r *GormRepository) Update(ctx context.Context, user *dusers.User) error {
	dbUser := r.domainToModel(user)

	result := r.db.WithContext(ctx).Save(&dbUser)
	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dusers.ErrUserNotFound
	}

	return nil
}

// Delete removes a user from the database
func (r *GormRepository) Delete(ctx context.Context, username string) error {
	result := r.db.WithContext(ctx).Where("username = ?", username).Delete(&models.User{})
	if result.Error != nil {
		return result.Error
	}

	if result.RowsAffected == 0 {
		return dusers.ErrUserNotFound
	}

	return nil
}

// List retrieves users with the given filters
func (r *GormRepository) List(ctx context.Context, filters dusers.ListFilters) ([]*dusers.User, error) {
	query := r.db.WithContext(ctx).Model(&models.User{})

	if filters.UserType != "" {
		query = query.Where("user_type = ?", filters.UserType)
	}

	if filters.Limit > 0 {
		query = query.Limit(filters.Limit)
	}

	if filters.Offset > 0 {
		query = query.Offset(filters.Offset)
	}

	query = query.Order("created_at DESC")

	var dbUsers []models.User
	if err := query.Find(&dbUsers).Error; err != nil {
		return nil, err
	}

	users := make([]*dusers.User, len(dbUsers))
	for i, dbUser := range dbUsers {
		users[i] = r.modelToDomain(&dbUser)
	}

	return users, nil
}

// ListUserBets retrieves all bets placed by the specified user ordered by placement time descending.
func (r *GormRepository) ListUserBets(ctx context.Context, username string) ([]*dusers.UserBet, error) {
	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("username = ?", username).
		Order("placed_at DESC").
		Find(&bets).Error; err != nil {
		return nil, err
	}

	result := make([]*dusers.UserBet, len(bets))
	for i, bet := range bets {
		result[i] = &dusers.UserBet{
			MarketID: bet.MarketID,
			PlacedAt: bet.PlacedAt,
		}
	}
	return result, nil
}

// GetMarketQuestion retrieves the question title for the specified market.
func (r *GormRepository) GetMarketQuestion(ctx context.Context, marketID uint) (string, error) {
	var market models.Market
	if err := r.db.WithContext(ctx).Select("question_title").Where("id = ?", marketID).First(&market).Error; err != nil {
		return "", err
	}
	return market.QuestionTitle, nil
}

// GetUserPositionInMarket calculates the user's position within the specified market.
func (r *GormRepository) GetUserPositionInMarket(ctx context.Context, marketID int64, username string) (*dusers.MarketUserPosition, error) {
	var market models.Market
	if err := r.db.WithContext(ctx).First(&market, marketID).Error; err != nil {
		return nil, err
	}

	var bets []models.Bet
	if err := r.db.WithContext(ctx).
		Where("market_id = ?", marketID).
		Order("placed_at ASC").
		Find(&bets).Error; err != nil {
		return nil, err
	}

	snapshot := positionsmath.MarketSnapshot{
		ID:               int64(market.ID),
		CreatedAt:        market.CreatedAt,
		IsResolved:       market.IsResolved,
		ResolutionResult: market.ResolutionResult,
	}

	boundaryBets := make([]boundary.Bet, len(bets))
	for i := range bets {
		boundaryBets[i] = boundary.Bet{
			ID:        uint(bets[i].ID),
			Username:  bets[i].Username,
			MarketID:  bets[i].MarketID,
			Amount:    bets[i].Amount,
			PlacedAt:  bets[i].PlacedAt,
			Outcome:   bets[i].Outcome,
			CreatedAt: bets[i].CreatedAt,
		}
	}

	position, err := positionsmath.CalculateMarketPositionForUser_WPAM_DBPM(snapshot, boundaryBets, username)
	if err != nil {
		return nil, err
	}

	return &dusers.MarketUserPosition{
		YesSharesOwned: position.YesSharesOwned,
		NoSharesOwned:  position.NoSharesOwned,
	}, nil
}

// ListUserMarkets returns markets the user has participated in ordered by last bet time.
func (r *GormRepository) ListUserMarkets(ctx context.Context, userID int64) ([]*dusers.UserMarket, error) {
	var dbMarkets []models.Market

	query := r.db.WithContext(ctx).Table("markets").
		Joins("join bets on bets.market_id = markets.id").
		Where("bets.user_id = ?", userID).
		Order("bets.created_at DESC").
		Distinct("markets.*").
		Find(&dbMarkets)

	if query.Error != nil {
		return nil, query.Error
	}

	markets := make([]*dusers.UserMarket, len(dbMarkets))
	for i, m := range dbMarkets {
		markets[i] = &dusers.UserMarket{
			ID:                      m.ID,
			QuestionTitle:           m.QuestionTitle,
			Description:             m.Description,
			OutcomeType:             m.OutcomeType,
			ResolutionDateTime:      m.ResolutionDateTime,
			FinalResolutionDateTime: m.FinalResolutionDateTime,
			UTCOffset:               m.UTCOffset,
			IsResolved:              m.IsResolved,
			ResolutionResult:        m.ResolutionResult,
			InitialProbability:      m.InitialProbability,
			YesLabel:                m.YesLabel,
			NoLabel:                 m.NoLabel,
			CreatorUsername:         m.CreatorUsername,
			CreatedAt:               m.CreatedAt,
			UpdatedAt:               m.UpdatedAt,
		}
	}

	return markets, nil
}

// GetCredentials returns the hashed password and password-change flag for the specified user.
func (r *GormRepository) GetCredentials(ctx context.Context, username string) (*dusers.Credentials, error) {
	var user models.User
	if err := r.db.WithContext(ctx).
		Select("password", "must_change_password").
		Where("username = ?", username).
		Take(&user).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dusers.ErrUserNotFound
		}
		return nil, err
	}

	return &dusers.Credentials{
		PasswordHash:       user.Password,
		MustChangePassword: user.MustChangePassword,
	}, nil
}

// FindAuthenticatedUser returns the login-facing user fields while containing persistence details in the repository edge.
func (r *GormRepository) FindAuthenticatedUser(ctx context.Context, username string) (*boundary.AuthenticatedUser, error) {
	var user authenticatedUserRow
	if err := r.db.WithContext(ctx).
		Table("users").
		Select("username", "user_type", "password", "must_change_password").
		Where("username = ?", username).
		Take(&user).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, dusers.ErrUserNotFound
		}
		return nil, err
	}

	return &boundary.AuthenticatedUser{
		Username:           user.Username,
		UserType:           user.UserType,
		PasswordHash:       user.Password,
		MustChangePassword: user.MustChangePassword,
	}, nil
}

// UpdatePassword persists a new password hash and updates the must-change flag.
