		PersonalLink3:         dbUser.PersonalLink3,
		PersonalLink4:         dbUser.PersonalLink4,
		APIKey:                dbUser.APIKey,
		MustChangePassword:    dbUser.MustChangePassword,
		CreatedAt:             dbUser.CreatedAt,
		UpdatedAt:             dbUser.UpdatedAt,
	}
}

